import{_ as a,o,c as r,ag as t}from"./chunks/framework.OsDJF_Ea.js";const p=JSON.parse('{"title":"Troubleshooting","description":"","frontmatter":{},"headers":[],"relativePath":"reference/troubleshooting.md","filePath":"reference/troubleshooting.md"}'),i={name:"reference/troubleshooting.md"};function s(l,e,n,d,h,c){return o(),r("div",null,[...e[0]||(e[0]=[t('<h1 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">â€‹</a></h1><p>Common issues and how to resolve them.</p><h2 id="connection-issues" tabindex="-1">Connection Issues <a class="header-anchor" href="#connection-issues" aria-label="Permalink to &quot;Connection Issues&quot;">â€‹</a></h2><h3 id="no-serial-port-appears-in-the-browser-dialog" tabindex="-1">No serial port appears in the browser dialog <a class="header-anchor" href="#no-serial-port-appears-in-the-browser-dialog" aria-label="Permalink to &quot;No serial port appears in the browser dialog&quot;">â€‹</a></h3><ul><li>Make sure you&#39;re using <strong>Chrome or Edge</strong> (Web Serial is not supported in Firefox/Safari)</li><li>Check the USB cable is <strong>data-capable</strong> (charge-only cables won&#39;t work)</li><li>Close any other application using the serial port (Arduino IDE, PlatformIO, serial monitors)</li><li>Try pressing the <strong>RESET</strong> button on the board</li><li>Try a different USB port on your computer</li></ul><h3 id="connection-drops-or-becomes-unresponsive" tabindex="-1">Connection drops or becomes unresponsive <a class="header-anchor" href="#connection-drops-or-becomes-unresponsive" aria-label="Permalink to &quot;Connection drops or becomes unresponsive&quot;">â€‹</a></h3><ul><li>Use a shorter USB cable or avoid USB hubs</li><li>The board may have crashed -- press RESET and reconnect</li><li>High CPU patches (90%+) can cause serial to become slow</li></ul><h3 id="board-doesn-t-appear-after-flashing" tabindex="-1">Board doesn&#39;t appear after flashing <a class="header-anchor" href="#board-doesn-t-appear-after-flashing" aria-label="Permalink to &quot;Board doesn&#39;t appear after flashing&quot;">â€‹</a></h3><ul><li>Press the <strong>RESET</strong> button -- ESP32-S3 often needs a manual reset after firmware upload</li><li>If that doesn&#39;t work, enter bootloader mode (hold BOOT + press RESET) and reflash</li></ul><h2 id="audio-issues" tabindex="-1">Audio Issues <a class="header-anchor" href="#audio-issues" aria-label="Permalink to &quot;Audio Issues&quot;">â€‹</a></h2><h3 id="no-sound" tabindex="-1">No sound <a class="header-anchor" href="#no-sound" aria-label="Permalink to &quot;No sound&quot;">â€‹</a></h3><ul><li>Check that your patch includes a <strong>Stereo Out</strong> module connected to your audio chain</li><li>Verify headphones or speakers are plugged into the audio output jack</li><li>Check the serial console (<code>STATUS</code> command) -- is a patch loaded?</li><li>Make sure module gain parameters aren&#39;t at zero</li></ul><h3 id="clicking-or-glitching-audio" tabindex="-1">Clicking or glitching audio <a class="header-anchor" href="#clicking-or-glitching-audio" aria-label="Permalink to &quot;Clicking or glitching audio&quot;">â€‹</a></h3><ul><li>Check CPU usage with the <code>PERF</code> serial command</li><li>Reduce module count or switch to lighter alternatives</li><li>Remove unused modules (each module uses CPU even if not connected)</li><li>Reverb in &quot;Ultra&quot; quality mode uses significant CPU -- try &quot;Standard&quot;</li></ul><h3 id="hum-or-noise" tabindex="-1">Hum or noise <a class="header-anchor" href="#hum-or-noise" aria-label="Permalink to &quot;Hum or noise&quot;">â€‹</a></h3><ul><li>Use a quality USB power supply (avoid cheap chargers)</li><li>If using Stereo In, check your input source levels</li></ul><h2 id="patch-issues" tabindex="-1">Patch Issues <a class="header-anchor" href="#patch-issues" aria-label="Permalink to &quot;Patch Issues&quot;">â€‹</a></h2><h3 id="patch-upload-fails" tabindex="-1">Patch upload fails <a class="header-anchor" href="#patch-upload-fails" aria-label="Permalink to &quot;Patch upload fails&quot;">â€‹</a></h3><ul><li>Ensure the serial connection is active (connected indicator in toolbar)</li><li>Try disconnecting and reconnecting</li><li>Check the serial console for error messages</li><li>Very large patches may need multiple upload attempts</li></ul><h3 id="parameters-don-t-respond-to-pots" tabindex="-1">Parameters don&#39;t respond to pots <a class="header-anchor" href="#parameters-don-t-respond-to-pots" aria-label="Permalink to &quot;Parameters don&#39;t respond to pots&quot;">â€‹</a></h3><ul><li>Check you&#39;re on the correct <strong>bank</strong> (turn encoder to switch)</li><li>Remember <strong>soft takeover</strong> -- the pot must cross the stored value before it takes effect</li><li>Verify the pot module is connected to the correct parameter input</li></ul><h2 id="sd-card-issues" tabindex="-1">SD Card Issues <a class="header-anchor" href="#sd-card-issues" aria-label="Permalink to &quot;SD Card Issues&quot;">â€‹</a></h2><h3 id="sd-card-not-detected" tabindex="-1">SD card not detected <a class="header-anchor" href="#sd-card-not-detected" aria-label="Permalink to &quot;SD card not detected&quot;">â€‹</a></h3><ul><li>Format the card as <strong>FAT32</strong> (not exFAT or NTFS)</li><li>Use a card 32GB or smaller for best compatibility</li><li>Re-seat the card and press RESET</li></ul><h3 id="sample-upload-fails" tabindex="-1">Sample upload fails <a class="header-anchor" href="#sample-upload-fails" aria-label="Permalink to &quot;Sample upload fails&quot;">â€‹</a></h3><ul><li>Check CPU usage -- high CPU (93%+) can interfere with file transfers</li><li>The transfer uses slower timing at high CPU load -- wait for it to complete</li><li>Try uploading fewer samples at once</li></ul><h2 id="recovery" tabindex="-1">Recovery <a class="header-anchor" href="#recovery" aria-label="Permalink to &quot;Recovery&quot;">â€‹</a></h2><h3 id="board-is-completely-unresponsive" tabindex="-1">Board is completely unresponsive <a class="header-anchor" href="#board-is-completely-unresponsive" aria-label="Permalink to &quot;Board is completely unresponsive&quot;">â€‹</a></h3><ol><li>Unplug the USB cable</li><li>Hold the <strong>BOOT</strong> button on the board</li><li>While holding BOOT, plug in the USB cable</li><li>Release BOOT -- the board is now in bootloader mode</li><li>Flash the firmware using the patcher&#39;s firmware update tool</li><li>Press RESET after flashing</li></ol>',29)])])}const m=a(i,[["render",s]]);export{p as __pageData,m as default};
